+  EXPECT_EQ("bool", from_msg_true.get_type_name());
+  EXPECT_TRUE(from_msg_true.get_value<rclcpp::parameter::ParameterType::PARAMETER_BOOL>());
+  EXPECT_TRUE(from_msg_true.get_parameter_value().bool_value);
